        double w3r, w3i;
        w3r = (w1r)*(w2r)-((w1i)*(w2i));
        w3i = (w1r)*(w2i)+((w1i)*(w2r));
        double w4r, w4i;
        w4r = (w2r)*(w2r)-((w2i)*(w2i));
        w4i = (w2r)*(w2i)+((w2i)*(w2r));
        double w5r, w5i;
        w5r = (w1r)*(w4r)-((w1i)*(w4i));
        w5i = (w1r)*(w4i)+((w1i)*(w4r));
        double w6r, w6i;
        w6r = (w3r)*(w3r)-((w3i)*(w3i));
        w6i = (w3r)*(w3i)+((w3i)*(w3r));
        double w7r, w7i;
        w7r = (w3r)*(w4r)-((w3i)*(w4i));
        w7i = (w3r)*(w4i)+((w3i)*(w4r));
        double w8r, w8i;
        w8r = (w4r)*(w4r)-((w4i)*(w4i));
        w8i = (w4r)*(w4i)+((w4i)*(w4r));
        double w9r, w9i;
        w9r = (w4r)*(w5r)-((w4i)*(w5i));
