        spill_re[5] = x0_re; spill_im[5] = x0_im;
        spill_re[6] = x1_re; spill_im[6] = x1_im;
        spill_re[7] = x2_re; spill_im[7] = x2_im;
        spill_re[8] = x3_re; spill_im[8] = x3_im;
        spill_re[9] = x4_re; spill_im[9] = x4_im;

        /* PASS 2: 5x radix-2 columns */

        /* column k1=0 */
        x0_re = spill_re[0]; x0_im = spill_im[0];
        x1_re = spill_re[5]; x1_im = spill_im[5];

        /* radix-2 k1=0 [fwd] */
        { double tr=(x0_re)-(x1_re), ti=(x0_im)-(x1_im);
          x0_re=(x0_re)+(x1_re); x0_im=(x0_im)+(x1_im);
          x1_re=tr; x1_im=ti; }

        rio_re[m*ms+0*ios] = x0_re; rio_im[m*ms+0*ios] = x0_im;
