        rio_re[m*ms+3*ios] = x0_re; rio_im[m*ms+3*ios] = x0_im;
        rio_re[m*ms+8*ios] = x1_re; rio_im[m*ms+8*ios] = x1_im;

        /* column k1=4 */
        x0_re = spill_re[4]; x0_im = spill_im[4];
        x1_re = spill_re[9]; x1_im = spill_im[9];

        { double tr = x1_re;
          x1_re = (x1_re)*(tw_W10_4_re)-((x1_im)*(tw_W10_4_im));
          x1_im = (tr)*(tw_W10_4_im)+((x1_im)*(tw_W10_4_re)); }

        /* radix-2 k1=4 [fwd] */
        { double tr=(x0_re)-(x1_re), ti=(x0_im)-(x1_im);
          x0_re=(x0_re)+(x1_re); x0_im=(x0_im)+(x1_im);
          x1_re=tr; x1_im=ti; }

        rio_re[m*ms+4*ios] = x0_re; rio_im[m*ms+4*ios] = x0_im;
