static void
radix10_t1_dit_log3_bwd_scalar(
    double * __restrict__ rio_re, double * __restrict__ rio_im,
    const double * __restrict__ W_re, const double * __restrict__ W_im,
    size_t ios, size_t mb, size_t me, size_t ms)
{
    const double cA = 0.559016994374947451262869435595348477363586426;
    const double cB = 0.951056516295153531181938433292089030146598816;
    const double cC = 0.587785252292473137103456792829092592000961304;
    const double cD = 0.250000000000000000000000000000000000000000000;

    double spill_re[10], spill_im[10];

    double x0_re,x0_im,x1_re,x1_im,x2_re,x2_im,x3_re,x3_im,x4_re,x4_im;

    const double tw_W10_1_re = W10_1_re;
    const double tw_W10_1_im = W10_1_im;
    const double tw_W10_2_re = W10_2_re;
    const double tw_W10_2_im = W10_2_im;
    const double tw_W10_3_re = W10_3_re;
    const double tw_W10_3_im = W10_3_im;
    const double tw_W10_4_re = W10_4_re;
    const double tw_W10_4_im = W10_4_im;

    for (size_t m = mb; m < me; m++) {
        /* Log3: load W^1, derive W^2..W^9 (8 cmuls, depth-4 parallel chain) */
        /*   Chain: w2=w1*w1, w3=w1*w2, w4=w2*w2, w5=w1*w4, */
        /*          w6=w3*w3, w7=w3*w4, w8=w4*w4, w9=w4*w5 */
        /*   Critical path: w1->w2->w4->w8 = depth 4 (vs 8 serial) */
        const double w1r = W_re[0*me+m], w1i = W_im[0*me+m];
        double w2r, w2i;
        w2r = (w1r)*(w1r)-((w1i)*(w1i));
        w2i = (w1r)*(w1i)+((w1i)*(w1r));
        double w3r, w3i;
        w3r = (w1r)*(w2r)-((w1i)*(w2i));
        w3i = (w1r)*(w2i)+((w1i)*(w2r));
        double w4r, w4i;
        w4r = (w2r)*(w2r)-((w2i)*(w2i));
        w4i = (w2r)*(w2i)+((w2i)*(w2r));
        double w5r, w5i;
        w5r = (w1r)*(w4r)-((w1i)*(w4i));
        w5i = (w1r)*(w4i)+((w1i)*(w4r));
        double w6r, w6i;
        w6r = (w3r)*(w3r)-((w3i)*(w3i));
        w6i = (w3r)*(w3i)+((w3i)*(w3r));
        double w7r, w7i;
        w7r = (w3r)*(w4r)-((w3i)*(w4i));
        w7i = (w3r)*(w4i)+((w3i)*(w4r));
        double w8r, w8i;
        w8r = (w4r)*(w4r)-((w4i)*(w4i));
        w8i = (w4r)*(w4i)+((w4i)*(w4r));
        double w9r, w9i;
        w9r = (w4r)*(w5r)-((w4i)*(w5i));
        w9i = (w4r)*(w5i)+((w4i)*(w5r));

        /* sub-FFT n2=0 */
        x0_re = rio_re[m*ms+0*ios]; x0_im = rio_im[m*ms+0*ios];
        x1_re = rio_re[m*ms+2*ios]; x1_im = rio_im[m*ms+2*ios];
        { double tr = x1_re;
          x1_re = (x1_re)*(w2r)+((x1_im)*(w2i));
          x1_im = (x1_im)*(w2r)-((tr)*(w2i)); }
        x2_re = rio_re[m*ms+4*ios]; x2_im = rio_im[m*ms+4*ios];
        { double tr = x2_re;
          x2_re = (x2_re)*(w4r)+((x2_im)*(w4i));
          x2_im = (x2_im)*(w4r)-((tr)*(w4i)); }
        x3_re = rio_re[m*ms+6*ios]; x3_im = rio_im[m*ms+6*ios];
        { double tr = x3_re;
          x3_re = (x3_re)*(w6r)+((x3_im)*(w6i));
          x3_im = (x3_im)*(w6r)-((tr)*(w6i)); }
        x4_re = rio_re[m*ms+8*ios]; x4_im = rio_im[m*ms+8*ios];
        { double tr = x4_re;
          x4_re = (x4_re)*(w8r)+((x4_im)*(w8i));
          x4_im = (x4_im)*(w8r)-((tr)*(w8i)); }

        /* radix-5 n2=0 [bwd] */
        {
        double s1r=(x1_re)+(x4_re), s1i=(x1_im)+(x4_im);
        double d1r=(x1_re)-(x4_re), d1i=(x1_im)-(x4_im);
        double s2r=(x2_re)+(x3_re), s2i=(x2_im)+(x3_im);
        double d2r=(x2_re)-(x3_re), d2i=(x2_im)-(x3_im);
        double ss_r=(s1r)+(s2r), ss_i=(s1i)+(s2i);
        double sd_r=(s1r)-(s2r), sd_i=(s1i)-(s2i);
        double t0r=(x0_re)-(cD)*(ss_r), t0i=(x0_im)-(cD)*(ss_i);
        x0_re=(x0_re)+(ss_r); x0_im=(x0_im)+(ss_i);
        double p1r=(cA)*(sd_r)+(t0r), p1i=(cA)*(sd_i)+(t0i);
        double p2r=(t0r)-(cA)*(sd_r), p2i=(t0i)-(cA)*(sd_i);
        double qar=(cC)*(d2i)+((cB)*(d1i)), qai=(cC)*(d2r)+((cB)*(d1r));
        double qbr=(cB)*(d2i)-((cC)*(d1i)), qbi=(cB)*(d2r)-((cC)*(d1r));
        x1_re=(p1r)-(qar); x1_im=(p1i)+(qai);
        x4_re=(p1r)+(qar); x4_im=(p1i)-(qai);
        x2_re=(p2r)+(qbr); x2_im=(p2i)-(qbi);
        x3_re=(p2r)-(qbr); x3_im=(p2i)+(qbi);
        }

        spill_re[0] = x0_re; spill_im[0] = x0_im;
        spill_re[1] = x1_re; spill_im[1] = x1_im;
        spill_re[2] = x2_re; spill_im[2] = x2_im;
        spill_re[3] = x3_re; spill_im[3] = x3_im;
        spill_re[4] = x4_re; spill_im[4] = x4_im;

        /* sub-FFT n2=1 */
        x0_re = rio_re[m*ms+1*ios]; x0_im = rio_im[m*ms+1*ios];
        { double tr = x0_re;
          x0_re = (x0_re)*(w1r)+((x0_im)*(w1i));
          x0_im = (x0_im)*(w1r)-((tr)*(w1i)); }
        x1_re = rio_re[m*ms+3*ios]; x1_im = rio_im[m*ms+3*ios];
        { double tr = x1_re;
          x1_re = (x1_re)*(w3r)+((x1_im)*(w3i));
          x1_im = (x1_im)*(w3r)-((tr)*(w3i)); }
        x2_re = rio_re[m*ms+5*ios]; x2_im = rio_im[m*ms+5*ios];
        { double tr = x2_re;
          x2_re = (x2_re)*(w5r)+((x2_im)*(w5i));
          x2_im = (x2_im)*(w5r)-((tr)*(w5i)); }
        x3_re = rio_re[m*ms+7*ios]; x3_im = rio_im[m*ms+7*ios];
        { double tr = x3_re;
          x3_re = (x3_re)*(w7r)+((x3_im)*(w7i));
          x3_im = (x3_im)*(w7r)-((tr)*(w7i)); }
        x4_re = rio_re[m*ms+9*ios]; x4_im = rio_im[m*ms+9*ios];
        { double tr = x4_re;
          x4_re = (x4_re)*(w9r)+((x4_im)*(w9i));
          x4_im = (x4_im)*(w9r)-((tr)*(w9i)); }

        /* radix-5 n2=1 [bwd] */
        {
        double s1r=(x1_re)+(x4_re), s1i=(x1_im)+(x4_im);
        double d1r=(x1_re)-(x4_re), d1i=(x1_im)-(x4_im);
        double s2r=(x2_re)+(x3_re), s2i=(x2_im)+(x3_im);
        double d2r=(x2_re)-(x3_re), d2i=(x2_im)-(x3_im);
        double ss_r=(s1r)+(s2r), ss_i=(s1i)+(s2i);
        double sd_r=(s1r)-(s2r), sd_i=(s1i)-(s2i);
        double t0r=(x0_re)-(cD)*(ss_r), t0i=(x0_im)-(cD)*(ss_i);
        x0_re=(x0_re)+(ss_r); x0_im=(x0_im)+(ss_i);
        double p1r=(cA)*(sd_r)+(t0r), p1i=(cA)*(sd_i)+(t0i);
        double p2r=(t0r)-(cA)*(sd_r), p2i=(t0i)-(cA)*(sd_i);
        double qar=(cC)*(d2i)+((cB)*(d1i)), qai=(cC)*(d2r)+((cB)*(d1r));
        double qbr=(cB)*(d2i)-((cC)*(d1i)), qbi=(cB)*(d2r)-((cC)*(d1r));
        x1_re=(p1r)-(qar); x1_im=(p1i)+(qai);
        x4_re=(p1r)+(qar); x4_im=(p1i)-(qai);
        x2_re=(p2r)+(qbr); x2_im=(p2i)-(qbi);
        x3_re=(p2r)-(qbr); x3_im=(p2i)+(qbi);
        }

        spill_re[5] = x0_re; spill_im[5] = x0_im;
        spill_re[6] = x1_re; spill_im[6] = x1_im;
        spill_re[7] = x2_re; spill_im[7] = x2_im;
        spill_re[8] = x3_re; spill_im[8] = x3_im;
        spill_re[9] = x4_re; spill_im[9] = x4_im;

        /* PASS 2: 5x radix-2 columns */

        /* column k1=0 */
        x0_re = spill_re[0]; x0_im = spill_im[0];
        x1_re = spill_re[5]; x1_im = spill_im[5];

        /* radix-2 k1=0 [bwd] */
        { double tr=(x0_re)-(x1_re), ti=(x0_im)-(x1_im);
          x0_re=(x0_re)+(x1_re); x0_im=(x0_im)+(x1_im);
          x1_re=tr; x1_im=ti; }

        rio_re[m*ms+0*ios] = x0_re; rio_im[m*ms+0*ios] = x0_im;
        rio_re[m*ms+5*ios] = x1_re; rio_im[m*ms+5*ios] = x1_im;

        /* column k1=1 */
        x0_re = spill_re[1]; x0_im = spill_im[1];
        x1_re = spill_re[6]; x1_im = spill_im[6];

        { double tr = x1_re;
          x1_re = (x1_re)*(tw_W10_1_re)+((x1_im)*(tw_W10_1_im));
          x1_im = (x1_im)*(tw_W10_1_re)-((tr)*(tw_W10_1_im)); }

        /* radix-2 k1=1 [bwd] */
        { double tr=(x0_re)-(x1_re), ti=(x0_im)-(x1_im);
          x0_re=(x0_re)+(x1_re); x0_im=(x0_im)+(x1_im);
          x1_re=tr; x1_im=ti; }

        rio_re[m*ms+1*ios] = x0_re; rio_im[m*ms+1*ios] = x0_im;
        rio_re[m*ms+6*ios] = x1_re; rio_im[m*ms+6*ios] = x1_im;

        /* column k1=2 */
        x0_re = spill_re[2]; x0_im = spill_im[2];
        x1_re = spill_re[7]; x1_im = spill_im[7];

        { double tr = x1_re;
          x1_re = (x1_re)*(tw_W10_2_re)+((x1_im)*(tw_W10_2_im));
          x1_im = (x1_im)*(tw_W10_2_re)-((tr)*(tw_W10_2_im)); }

        /* radix-2 k1=2 [bwd] */
        { double tr=(x0_re)-(x1_re), ti=(x0_im)-(x1_im);
          x0_re=(x0_re)+(x1_re); x0_im=(x0_im)+(x1_im);
          x1_re=tr; x1_im=ti; }

        rio_re[m*ms+2*ios] = x0_re; rio_im[m*ms+2*ios] = x0_im;
        rio_re[m*ms+7*ios] = x1_re; rio_im[m*ms+7*ios] = x1_im;

        /* column k1=3 */
        x0_re = spill_re[3]; x0_im = spill_im[3];
        x1_re = spill_re[8]; x1_im = spill_im[8];

        { double tr = x1_re;
          x1_re = (x1_re)*(tw_W10_3_re)+((x1_im)*(tw_W10_3_im));
          x1_im = (x1_im)*(tw_W10_3_re)-((tr)*(tw_W10_3_im)); }

        /* radix-2 k1=3 [bwd] */
        { double tr=(x0_re)-(x1_re), ti=(x0_im)-(x1_im);
          x0_re=(x0_re)+(x1_re); x0_im=(x0_im)+(x1_im);
          x1_re=tr; x1_im=ti; }

        rio_re[m*ms+3*ios] = x0_re; rio_im[m*ms+3*ios] = x0_im;
        rio_re[m*ms+8*ios] = x1_re; rio_im[m*ms+8*ios] = x1_im;

        /* column k1=4 */
        x0_re = spill_re[4]; x0_im = spill_im[4];
        x1_re = spill_re[9]; x1_im = spill_im[9];

        { double tr = x1_re;
          x1_re = (x1_re)*(tw_W10_4_re)+((x1_im)*(tw_W10_4_im));
          x1_im = (x1_im)*(tw_W10_4_re)-((tr)*(tw_W10_4_im)); }

        /* radix-2 k1=4 [bwd] */
        { double tr=(x0_re)-(x1_re), ti=(x0_im)-(x1_im);
          x0_re=(x0_re)+(x1_re); x0_im=(x0_im)+(x1_im);
          x1_re=tr; x1_im=ti; }

        rio_re[m*ms+4*ios] = x0_re; rio_im[m*ms+4*ios] = x0_im;
        rio_re[m*ms+9*ios] = x1_re; rio_im[m*ms+9*ios] = x1_im;

    }
}


#undef LD
#undef ST

